// Discrete Choice DGP Generators
// ============================================

fn generate_count_data(n: usize, seed: u64) -> Dataset {
    let mut rng = ChaCha8Rng::seed_from_u64(seed);
    let x1: Vec<f64> = (0..n).map(|_| rng.gen_range(-1.0..1.0)).collect();
    let x2: Vec<f64> = (0..n).map(|_| rng.gen_range(-1.0..1.0)).collect();
    let group: Vec<i64> = (0..n).map(|i| (i % 5) as i64).collect();
    let y: Vec<f64> = (0..n)
        .map(|i| {
            let lambda = (0.5 + 0.3 * x1[i] + 0.2 * x2[i]).exp();
            // Poisson random via inverse CDF
            let u: f64 = rng.gen_range(0.0_f64..1.0_f64);
            let mut k = 0.0;
            let mut p = (-lambda).exp();
            let mut cum = p;
            while cum < u && k < 100.0 {
                k += 1.0;
                p *= lambda / k;
                cum += p;
            }
            k
        })
        .collect();
    let df = df! { "y" => y, "x1" => x1, "x2" => x2, "group" => group }
        .expect("count data");
    Dataset::new(df)
}

fn generate_zeroinfl_data(n: usize, seed: u64) -> Dataset {
    let mut rng = ChaCha8Rng::seed_from_u64(seed);
    let x1: Vec<f64> = (0..n).map(|_| rng.gen_range(-1.0..1.0)).collect();
    let x2: Vec<f64> = (0..n).map(|_| rng.gen_range(-1.0..1.0)).collect();
    let y: Vec<f64> = (0..n)
        .map(|i| {
            // 30% structural zeros
            if rng.gen_range(0.0_f64..1.0_f64) < 0.3 {
                return 0.0;
            }
            let lambda = (0.5 + 0.3 * x1[i] + 0.2 * x2[i]).exp();
            let u: f64 = rng.gen_range(0.0_f64..1.0_f64);
            let mut k = 0.0;
            let mut p = (-lambda).exp();
            let mut cum = p;
            while cum < u && k < 100.0 {
                k += 1.0;
                p *= lambda / k;
                cum += p;
            }
            k
        })
        .collect();
    let df = df! { "y" => y, "x1" => x1, "x2" => x2 }.expect("zeroinfl data");
    Dataset::new(df)
}

fn generate_ordered_data(n: usize, seed: u64) -> Dataset {
    let mut rng = ChaCha8Rng::seed_from_u64(seed);
    let x1: Vec<f64> = (0..n).map(|_| rng.gen_range(-2.0..2.0)).collect();
    let x2: Vec<f64> = (0..n).map(|_| rng.gen_range(-2.0..2.0)).collect();
    let y: Vec<String> = (0..n)
        .map(|i| {
            // Logistic noise
            let u: f64 = rng.gen_range(0.001_f64..0.999_f64);
            let logistic_noise = (u / (1.0 - u)).ln();
            let y_star = 0.5 * x1[i] + 0.3 * x2[i] + logistic_noise;
            if y_star < -0.5 {
                "1".to_string()
            } else if y_star < 0.5 {
                "2".to_string()
            } else {
                "3".to_string()
            }
        })
        .collect();
    let df = df! { "y" => y, "x1" => x1, "x2" => x2 }.expect("ordered data");
    Dataset::new(df)
}

fn generate_multinomial_data(n: usize, seed: u64) -> Dataset {
    let mut rng = ChaCha8Rng::seed_from_u64(seed);
    let x1: Vec<f64> = (0..n).map(|_| rng.gen_range(-2.0..2.0)).collect();
    let x2: Vec<f64> = (0..n).map(|_| rng.gen_range(-2.0..2.0)).collect();
    let y: Vec<String> = (0..n)
        .map(|i| {
            // 3 categories with utility model
            let u1 = 0.5 * x1[i] + 0.2 * x2[i] + rng.gen_range(-1.0..1.0);
            let u2 = -0.3 * x1[i] + 0.4 * x2[i] + rng.gen_range(-1.0..1.0);
            let u3 = rng.gen_range(-1.0..1.0); // reference
            if u1 >= u2 && u1 >= u3 {
                "A".to_string()
            } else if u2 >= u3 {
                "B".to_string()
            } else {
                "C".to_string()
            }
        })
        .collect();
    let df = df! { "y" => y, "x1" => x1, "x2" => x2 }.expect("multinomial data");
    Dataset::new(df)
}

fn generate_garch_data(n: usize, seed: u64) -> Vec<f64> {
    let mut rng = ChaCha8Rng::seed_from_u64(seed);
    let normal = Normal::new(0.0_f64, 1.0_f64).unwrap();
    let omega: f64 = 0.1;
    let alpha: f64 = 0.15;
    let beta: f64 = 0.75;
    let mut y: Vec<f64> = vec![0.0; n];
    let mut sigma2: Vec<f64> = vec![0.0; n];
    sigma2[0] = omega / (1.0 - alpha - beta);
    y[0] = sigma2[0].sqrt() * normal.sample(&mut rng);
    for t in 1..n {
        sigma2[t] = omega + alpha * y[t - 1].powi(2) + beta * sigma2[t - 1];
        y[t] = sigma2[t].sqrt() * normal.sample(&mut rng);
    }
    y
}

fn generate_bivariate_data(n: usize, seed: u64) -> Dataset {
    let mut rng = ChaCha8Rng::seed_from_u64(seed);
    let normal = Normal::new(0.0_f64, 0.5_f64).unwrap();
    let mut y1: Vec<f64> = vec![0.0; n];
    let mut y2: Vec<f64> = vec![0.0; n];
    y1[0] = Normal::new(0.0_f64, 1.0_f64).unwrap().sample(&mut rng);
    y2[0] = Normal::new(0.0_f64, 1.0_f64).unwrap().sample(&mut rng);
    for t in 1..n {
        y1[t] = 0.5 * y1[t - 1] + 0.1 * y2[t - 1] + normal.sample(&mut rng);
        y2[t] = 0.2 * y1[t - 1] + 0.6 * y2[t - 1] + normal.sample(&mut rng);
    }
    let df = df! { "y1" => y1, "y2" => y2 }.expect("bivariate data");
    Dataset::new(df)
}

/// Extract column from dataset as Vec<f64>
fn extract_col_vec(dataset: &Dataset, col: &str) -> Vec<f64> {
    let series = dataset.df().column(col).unwrap().as_materialized_series().clone();
    let casted = series.cast(&polars::prelude::DataType::Float64).unwrap();
    casted.f64().unwrap()
        .into_iter().map(|v| v.unwrap_or(0.0)).collect()
}

