        let b = (n as f64 * 0.2) as f64;
        let c = (n as f64 * 0.15) as f64;
        let d = n as f64 - a - b - c;
        let table = [[a, b], [c, d]];

        let mut result = run_benchmark_tracked("Fisher", "twosided", n, &config, || {
            fisher_exact_test(&table, FisherAlternative::TwoSided, None)
        });
        if let Ok(ref res) = fisher_exact_test(&table, FisherAlternative::TwoSided, None) {
            let mut outputs = BTreeMap::new();
            capture(&mut outputs, "statistic", res.odds_ratio);
            capture(&mut outputs, "p_value", res.p_value);
            result.outputs = outputs;
        }
        result.dgp = "fisher".to_string();
        result.seed = 42;
        print_result(&result);
        results.push(result);
